59: // Helper method that ensures that we've setting flags based on all the health flag values on the
60: // host.
61: void setHealthFlag(Upstream::Host::HealthFlag flag, const Upstream::Host& host,
62:                    envoy::admin::v3::HostHealthStatus& health_status) {
63:   switch (flag) {
64:   case Upstream::Host::HealthFlag::FAILED_ACTIVE_HC:
65:     health_status.set_failed_active_health_check(
66:         host.healthFlagGet(Upstream::Host::HealthFlag::FAILED_ACTIVE_HC));
67:     break;
68:   case Upstream::Host::HealthFlag::FAILED_OUTLIER_CHECK:
69:     health_status.set_failed_outlier_check(
70:         host.healthFlagGet(Upstream::Host::HealthFlag::FAILED_OUTLIER_CHECK));
71:     break;
72:   case Upstream::Host::HealthFlag::FAILED_EDS_HEALTH:
73:   case Upstream::Host::HealthFlag::DEGRADED_EDS_HEALTH:
74:     if (host.healthFlagGet(Upstream::Host::HealthFlag::FAILED_EDS_HEALTH)) {
75:       health_status.set_eds_health_status(envoy::config::core::v3::UNHEALTHY);
76:     } else if (host.healthFlagGet(Upstream::Host::HealthFlag::DEGRADED_EDS_HEALTH)) {
77:       health_status.set_eds_health_status(envoy::config::core::v3::DEGRADED);
78:     } else {
79:       health_status.set_eds_health_status(envoy::config::core::v3::HEALTHY);
80:     }
81:     break;
82:   case Upstream::Host::HealthFlag::DEGRADED_ACTIVE_HC:
83:     health_status.set_failed_active_degraded_check(
84:         host.healthFlagGet(Upstream::Host::HealthFlag::DEGRADED_ACTIVE_HC));
85:     break;
86:   case Upstream::Host::HealthFlag::PENDING_DYNAMIC_REMOVAL:
87:     health_status.set_pending_dynamic_removal(
88:         host.healthFlagGet(Upstream::Host::HealthFlag::PENDING_DYNAMIC_REMOVAL));
89:     break;
90:   case Upstream::Host::HealthFlag::PENDING_ACTIVE_HC:
91:     health_status.set_pending_active_hc(
92:         host.healthFlagGet(Upstream::Host::HealthFlag::PENDING_ACTIVE_HC));
93:     break;
94:   case Upstream::Host::HealthFlag::EXCLUDED_VIA_IMMEDIATE_HC_FAIL:
95:     health_status.set_excluded_via_immediate_hc_fail(
96:         host.healthFlagGet(Upstream::Host::HealthFlag::EXCLUDED_VIA_IMMEDIATE_HC_FAIL));
97:     break;
98:   case Upstream::Host::HealthFlag::ACTIVE_HC_TIMEOUT:
99:     health_status.set_active_hc_timeout(
100:         host.healthFlagGet(Upstream::Host::HealthFlag::ACTIVE_HC_TIMEOUT));
101:     break;
102:   case Upstream::Host::HealthFlag::EDS_STATUS_DRAINING:
103:     if (host.healthFlagGet(Upstream::Host::HealthFlag::EDS_STATUS_DRAINING)) {
104:       health_status.set_eds_health_status(envoy::config::core::v3::DRAINING);
105:     }
106:     break;
107:   }
108: }
