110: // TODO(efimki): Add support of text readouts stats.
111: void ClustersHandler::writeClustersAsJson(Buffer::Instance& response) {
112:   envoy::admin::v3::Clusters clusters;
113:   // TODO(mattklein123): Add ability to see warming clusters in admin output.
114:   auto all_clusters = server_.clusterManager().clusters();
115:   for (const auto& [name, cluster_ref] : all_clusters.active_clusters_) {
116:     UNREFERENCED_PARAMETER(name);
117:     const Upstream::Cluster& cluster = cluster_ref.get();
118:     Upstream::ClusterInfoConstSharedPtr cluster_info = cluster.info();
119: 
120:     envoy::admin::v3::ClusterStatus& cluster_status = *clusters.add_cluster_statuses();
121:     cluster_status.set_name(cluster_info->name());
122:     cluster_status.set_observability_name(cluster_info->observabilityName());
123:     if (const auto& name = cluster_info->edsServiceName(); !name.empty()) {
124:       cluster_status.set_eds_service_name(name);
125:     }
126:     addCircuitBreakerSettingsAsJson(
127:         envoy::config::core::v3::RoutingPriority::DEFAULT,
128:         cluster.info()->resourceManager(Upstream::ResourcePriority::Default), cluster_status);
129:     addCircuitBreakerSettingsAsJson(
130:         envoy::config::core::v3::RoutingPriority::HIGH,
131:         cluster.info()->resourceManager(Upstream::ResourcePriority::High), cluster_status);
132: 
133:     const Upstream::Outlier::Detector* outlier_detector = cluster.outlierDetector();
134:     if (outlier_detector != nullptr &&
135:         outlier_detector->successRateEjectionThreshold(
136:             Upstream::Outlier::DetectorHostMonitor::SuccessRateMonitorType::ExternalOrigin) > 0.0) {
137:       cluster_status.mutable_success_rate_ejection_threshold()->set_value(
138:           outlier_detector->successRateEjectionThreshold(
139:               Upstream::Outlier::DetectorHostMonitor::SuccessRateMonitorType::ExternalOrigin));
140:     }
141:     if (outlier_detector != nullptr &&
142:         outlier_detector->successRateEjectionThreshold(
143:             Upstream::Outlier::DetectorHostMonitor::SuccessRateMonitorType::LocalOrigin) > 0.0) {
144:       cluster_status.mutable_local_origin_success_rate_ejection_threshold()->set_value(
145:           outlier_detector->successRateEjectionThreshold(
146:               Upstream::Outlier::DetectorHostMonitor::SuccessRateMonitorType::LocalOrigin));
147:     }
148: 
149:     cluster_status.set_added_via_api(cluster_info->addedViaApi());
150: 
151:     for (auto& host_set : cluster.prioritySet().hostSetsPerPriority()) {
152:       for (auto& host : host_set->hosts()) {
153:         envoy::admin::v3::HostStatus& host_status = *cluster_status.add_host_statuses();
154:         Network::Utility::addressToProtobufAddress(*host->address(),
155:                                                    *host_status.mutable_address());
156:         host_status.set_hostname(host->hostname());
157:         host_status.mutable_locality()->MergeFrom(host->locality());
158: 
159:         for (const auto& [counter_name, counter] : host->counters()) {
160:           auto& metric = *host_status.add_stats();
161:           metric.set_name(std::string(counter_name));
162:           metric.set_value(counter.get().value());
163:           metric.set_type(envoy::admin::v3::SimpleMetric::COUNTER);
164:         }
165: 
166:         for (const auto& [gauge_name, gauge] : host->gauges()) {
167:           auto& metric = *host_status.add_stats();
168:           metric.set_name(std::string(gauge_name));
169:           metric.set_value(gauge.get().value());
170:           metric.set_type(envoy::admin::v3::SimpleMetric::GAUGE);
171:         }
172: 
173:         envoy::admin::v3::HostHealthStatus& health_status = *host_status.mutable_health_status();
174: 
175: // Invokes setHealthFlag for each health flag.
176: #define SET_HEALTH_FLAG(name, notused)                                                             \
177:   setHealthFlag(Upstream::Host::HealthFlag::name, *host, health_status);
178:         HEALTH_FLAG_ENUM_VALUES(SET_HEALTH_FLAG)
179: #undef SET_HEALTH_FLAG
180: 
181:         double success_rate = host->outlierDetector().successRate(
182:             Upstream::Outlier::DetectorHostMonitor::SuccessRateMonitorType::ExternalOrigin);
183:         if (success_rate >= 0.0) {
184:           host_status.mutable_success_rate()->set_value(success_rate);
185:         }
186: 
187:         host_status.set_weight(host->weight());
188: 
189:         host_status.set_priority(host->priority());
190:         success_rate = host->outlierDetector().successRate(
191:             Upstream::Outlier::DetectorHostMonitor::SuccessRateMonitorType::LocalOrigin);
192:         if (success_rate >= 0.0) {
193:           host_status.mutable_local_origin_success_rate()->set_value(success_rate);
194:         }
195:       }
196:     }
197:   }
198:   response.add(MessageUtil::getJsonStringFromMessageOrError(clusters, true)); // pretty-print
199: }
