202: void ClustersHandler::writeClustersAsText(Buffer::Instance& response) {
203:   // TODO(mattklein123): Add ability to see warming clusters in admin output.
204:   auto all_clusters = server_.clusterManager().clusters();
205:   for (const auto& [name, cluster_ref] : all_clusters.active_clusters_) {
206:     UNREFERENCED_PARAMETER(name);
207:     const Upstream::Cluster& cluster = cluster_ref.get();
208:     const std::string& cluster_name = cluster.info()->name();
209:     response.add(fmt::format("{}::observability_name::{}\n", cluster_name,
210:                              cluster.info()->observabilityName()));
211:     addOutlierInfo(cluster_name, cluster.outlierDetector(), response);
212: 
213:     addCircuitBreakerSettingsAsText(
214:         cluster_name, "default",
215:         cluster.info()->resourceManager(Upstream::ResourcePriority::Default), response);
216:     addCircuitBreakerSettingsAsText(
217:         cluster_name, "high", cluster.info()->resourceManager(Upstream::ResourcePriority::High),
218:         response);
219: 
220:     response.add(
221:         fmt::format("{}::added_via_api::{}\n", cluster_name, cluster.info()->addedViaApi()));
222:     if (const auto& name = cluster.info()->edsServiceName(); !name.empty()) {
223:       response.add(fmt::format("{}::eds_service_name::{}\n", cluster_name, name));
224:     }
225:     for (auto& host_set : cluster.prioritySet().hostSetsPerPriority()) {
226:       for (auto& host : host_set->hosts()) {
227:         const std::string& host_address = host->address()->asString();
228:         std::map<absl::string_view, uint64_t> all_stats;
229:         for (const auto& [counter_name, counter] : host->counters()) {
230:           all_stats[counter_name] = counter.get().value();
231:         }
232: 
233:         for (const auto& [gauge_name, gauge] : host->gauges()) {
234:           all_stats[gauge_name] = gauge.get().value();
235:         }
236: 
237:         for (const auto& [stat_name, stat] : all_stats) {
238:           response.add(
239:               fmt::format("{}::{}::{}::{}\n", cluster_name, host_address, stat_name, stat));
240:         }
241: 
242:         response.add(
243:             fmt::format("{}::{}::hostname::{}\n", cluster_name, host_address, host->hostname()));
244:         response.add(fmt::format("{}::{}::health_flags::{}\n", cluster_name, host_address,
245:                                  Upstream::HostUtility::healthFlagsToString(*host)));
246:         response.add(
247:             fmt::format("{}::{}::weight::{}\n", cluster_name, host_address, host->weight()));
248:         response.add(fmt::format("{}::{}::region::{}\n", cluster_name, host_address,
249:                                  host->locality().region()));
250:         response.add(
251:             fmt::format("{}::{}::zone::{}\n", cluster_name, host_address, host->locality().zone()));
252:         response.add(fmt::format("{}::{}::sub_zone::{}\n", cluster_name, host_address,
253:                                  host->locality().sub_zone()));
254:         response.add(
255:             fmt::format("{}::{}::canary::{}\n", cluster_name, host_address, host->canary()));
256:         response.add(
257:             fmt::format("{}::{}::priority::{}\n", cluster_name, host_address, host->priority()));
258:         response.add(fmt::format(
259:             "{}::{}::success_rate::{}\n", cluster_name, host_address,
260:             host->outlierDetector().successRate(
261:                 Upstream::Outlier::DetectorHostMonitor::SuccessRateMonitorType::ExternalOrigin)));
262:         response.add(fmt::format(
263:             "{}::{}::local_origin_success_rate::{}\n", cluster_name, host_address,
264:             host->outlierDetector().successRate(
265:                 Upstream::Outlier::DetectorHostMonitor::SuccessRateMonitorType::LocalOrigin)));
266:       }
267:     }
268:   }
