25: Http::Code StatsHandler::handlerResetCounters(Http::ResponseHeaderMap&, Buffer::Instance& response,
26:                                               AdminStream&) {
27:   for (const Stats::CounterSharedPtr& counter : server_.stats().counters()) {
28:     counter->reset();
29:   }
30:   server_.stats().symbolTable().clearRecentLookups();
31:   response.add("OK\n");
32:   return Http::Code::OK;
33: }
