35: Http::Code StatsHandler::handlerStatsRecentLookups(Http::ResponseHeaderMap&,
36:                                                    Buffer::Instance& response, AdminStream&) {
37:   Stats::SymbolTable& symbol_table = server_.stats().symbolTable();
38:   std::string table;
39:   const uint64_t total =
40:       symbol_table.getRecentLookups([&table](absl::string_view name, uint64_t count) {
41:         table += fmt::format("{:8d} {}\n", count, name);
42:       });
43:   if (table.empty() && symbol_table.recentLookupCapacity() == 0) {
44:     table = "Lookup tracking is not enabled. Use /stats/recentlookups/enable to enable.\n";
45:   } else {
46:     response.add("   Count Lookup\n");
47:   }
48:   response.add(absl::StrCat(table, "\ntotal: ", total, "\n"));
49:   return Http::Code::OK;
50: }
