52: Http::Code StatsHandler::handlerStatsRecentLookupsClear(Http::ResponseHeaderMap&,
53:                                                         Buffer::Instance& response, AdminStream&) {
54:   server_.stats().symbolTable().clearRecentLookups();
55:   response.add("OK\n");
56:   return Http::Code::OK;
57: }
